SELECT COUNT(DISTINCT LP.PK) AS QUANTIDADE FROM LATTES_P_PRODTEC LPP JOIN LATTES_PRODTEC LP ON LP.PK = LPP.FK_PRODTEC JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LP.ANO = 2023 AND LOWER(LP.NATUREZA) LIKE LOWER('%parecer%') AND S.GENERO = 'MASCULINO' AND S.SIGLA_CAMPUS = 'ANA' AND LOWER(COALESCE(S.AREA_INGRESSO, S.AREA_INGRESSO_OG)) LIKE '%sociologia%'